#include <stdio.h>
#include <math.h>

int main() {
    int R;
    scanf("%d", &R);
    int count = 0;
    printf("%d\n", count);
    for (int a = 1; a <= 1000; a++) {
        for (int b = a; b <= 1000; b++) {
            for (int c = b; c <= 1000; c++) {
                if (a + b > c && a + c > b && b + c > a) {
                    double s = (a + b + c) / 2.0;
                    double area = sqrt(s * (s - a) * (s - b) * (s - c));
                    double r = area / s;
                    if (fabs(r - R) < 1e-9) {
                        count++;
                        printf("%d %d %d\n", a, b, c);
                    }
                }
            }
        }
    }
    return 0;
}

